/**
 * Architecture Map data + display config — living project memory.
 *
 * Source of truth: "Emergent Civilization Simulator — Ecology Architecture Sheet".
 * This is documentation only; it lives outside `src/sim` and never owns sim truth.
 *
 * To add a new system: add a node here, give it a cluster + scope + status, and
 * connect it with one or more links. Mark future work as scope "future"/"bridge"
 * (and add a "risk" node/link if it can go wrong) BEFORE implementing it, so new
 * systems never become detached random features.
 */

import type { SimulationLinkDatum, SimulationNodeDatum } from "d3-force";

export type ClusterKey =
  | "substrate"
  | "movement"
  | "pressure"
  | "demography"
  | "debug"
  | "bridge"
  | "food"
  | "fauna"
  | "culture"
  | "risk"
  | "futureInfra";

export type NodeScope = "current" | "bridge" | "future" | "risk";

export type LinkType =
  | "dependency"
  | "input"
  | "output"
  | "behavior"
  | "bridge"
  | "futureHook"
  | "feedback"
  | "risk";

export type ViewKey = "current" | "future" | "bridges" | "risks" | "dependency";

export type GraphNode = {
  readonly id: string;
  readonly label: string;
  readonly cluster: ClusterKey;
  readonly scope: NodeScope;
  readonly size: number;
  readonly status: string;
  readonly summary: string;
  readonly central?: boolean;
  readonly bridgeNeighbor?: boolean;
  readonly riskNeighbor?: boolean;
};

export type GraphLink = {
  readonly source: string;
  readonly target: string;
  readonly type: LinkType;
  readonly note: string;
};

/** Node after d3 has positioned it (adds x/y/vx/vy). */
export interface SimNode extends GraphNode, SimulationNodeDatum {
  radius: number;
}

/** Link after d3 has resolved source/target to SimNode objects. */
export interface SimLink extends SimulationLinkDatum<SimNode> {
  readonly type: LinkType;
  readonly note: string;
}

export type LinkStyle = {
  readonly color: string;
  readonly dash: string;
  readonly width: number;
  readonly label: string;
};

export type ViewConfig = {
  readonly label: string;
  readonly description: string;
  readonly includeNode: (node: GraphNode) => boolean;
  readonly includeLink: (link: GraphLink) => boolean;
};

