export const VIEWS: Record<ViewKey, ViewConfig> = {
  current: {
    label: "Current System Map",
    description: "Only implemented / partial / debug-only systems that exist now.",
    includeNode: (n) => n.scope === "current",
    includeLink: (l) => !["futureHook", "bridge", "risk"].includes(l.type),
  },
  future: {
    label: "Future / Needed System Map",
    description: "Future systems plus current anchor systems they must plug into.",
    includeNode: (n) =>
      n.scope === "future" || n.scope === "bridge" || (n.scope === "current" && n.bridgeNeighbor === true),
    includeLink: (l) => l.type !== "risk",
  },
  bridges: {
    label: "Missing Bridges",
    description: "Near-term bridge layer required before food/fauna/culture can be believable.",
    includeNode: (n) =>
      n.scope === "bridge" ||
      (n.scope === "current" && n.bridgeNeighbor === true) ||
      ["foodEcology", "fauna", "culture", "persistentCamps"].includes(n.id),
    includeLink: (l) => ["bridge", "dependency", "input", "output", "behavior"].includes(l.type),
  },
  risks: {
    label: "Risk Nodes",
    description: "Architecture, model, debug, determinism, and performance risks.",
    includeNode: (n) =>
      n.scope === "risk" ||
      n.riskNeighbor === true ||
      ["foodEcology", "fauna", "plantPatches", "persistentCamps", "religion", "settlement", "chronicles"].includes(n.id),
    includeLink: (l) =>
      l.type === "risk" ||
      (l.type === "bridge" &&
        ["sharedCatchment", "rawDebug", "resourceClass", "resourceKnowledge", "ecologyDebug", "catchmentPipeline"].includes(
          l.target,
        )),
  },
  dependency: {
    label: "Dependency Links",
    description: "Full dependency web: current systems, bridges, future systems, and risks.",
    includeNode: () => true,
    includeLink: () => true,
  },
};

/** Cluster anchor positions as fractions of the canvas, used by force-x/force-y. */
export function clusterPosition(cluster: ClusterKey, width: number, height: number): [number, number] {
  const map: Record<ClusterKey, [number, number]> = {
    substrate: [0.18, 0.23],
    movement: [0.32, 0.5],
    pressure: [0.5, 0.45],
    demography: [0.62, 0.62],
    debug: [0.76, 0.3],
    bridge: [0.48, 0.22],
    food: [0.24, 0.78],
    fauna: [0.72, 0.78],
    culture: [0.86, 0.52],
    futureInfra: [0.63, 0.22],
    risk: [0.9, 0.18],
  };
  const [x, y] = map[cluster];

  return [width * x, height * y];
}

export function wrapLabel(label: string, max = 16): string[] {
  const words = label.split(" ");
  const lines: string[] = [];
  let line = "";

  words.forEach((word) => {
    const next = line ? `${line} ${word}` : word;

    if (next.length > max && line) {
      lines.push(line);
      line = word;
    } else {
      line = next;
    }
  });

  if (line) {
    lines.push(line);
  }

  return lines.slice(0, 3);
}

export type VisibleGraph = {
  readonly nodes: readonly GraphNode[];
  readonly links: readonly GraphLink[];
};

/** Applies the active view filter + free-text search to produce the visible subgraph. */
export function visibleGraph(viewKey: ViewKey, query: string): VisibleGraph {
  const view = VIEWS[viewKey];
  const q = query.trim().toLowerCase();
  const baseNodes = NODES.filter(view.includeNode);
  const baseIds = new Set(baseNodes.map((n) => n.id));
  const baseLinks = LINKS.filter((l) => baseIds.has(l.source) && baseIds.has(l.target) && view.includeLink(l));

  if (!q) {
    return { nodes: baseNodes, links: baseLinks };
  }

  const matched = new Set(
    baseNodes.filter((n) => `${n.label} ${n.status} ${n.summary}`.toLowerCase().includes(q)).map((n) => n.id),
  );

  baseLinks.forEach((l) => {
    if (matched.has(l.source) || matched.has(l.target) || l.note.toLowerCase().includes(q)) {
      matched.add(l.source);
      matched.add(l.target);
    }
  });

  const filteredNodes = baseNodes.filter((n) => matched.has(n.id));
  const filteredIds = new Set(filteredNodes.map((n) => n.id));
  const filteredLinks = baseLinks.filter((l) => filteredIds.has(l.source) && filteredIds.has(l.target));

  return { nodes: filteredNodes, links: filteredLinks };
}

